import sys
from collections import deque

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1

    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx += 2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx += 1
            grid.append(list(row))
            for j, c in enumerate(row):
                if c == 'L':
                    lab = (i, j)

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]

        # Count free neighbors for each cell
        free_nb = [[0]*m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '#':
                    continue
                cnt = 0
                for di, dj in dirs:
                    ni, nj = i+di, j+dj
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        cnt += 1
                free_nb[i][j] = cnt

        good = [[False]*m for _ in range(n)]
        queue = deque()
        li, lj = lab
        good[li][lj] = True
        queue.append((li, lj))

        # non_good_nb[i][j] = number of free neighbors that are not yet good
        non_good_nb = [row[:] for row in free_nb]

        while queue:
            i, j = queue.popleft()
            for di, dj in dirs:
                ni, nj = i+di, j+dj
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not good[ni][nj]:
                    non_good_nb[ni][nj] -= 1
                    if non_good_nb[ni][nj] <= 1:
                        good[ni][nj] = True
                        queue.append((ni, nj))

        for i in range(n):
            for j in range(m):
                if grid[i][j] == '.' and good[i][j]:
                    grid[i][j] = '+'

        out = []
        for row in grid:
            out.append(''.join(row))
        print('\n'.join(out))

solve()

